#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    pid_t pid;
    int status;

    printf("Parent Process: PID = %d\n", getpid());

    pid = fork();  // Create new process

    if (pid < 0) {
        // Error occurred
        printf("Fork failed!\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child Process: PID = %d, Parent PID = %d\n", 
               getpid(), getppid());
        printf("Child completing execution\n");
        _exit(0);  // Child exits
    }
    else {
        // Parent process
        printf("Parent: Created child with PID = %d\n", pid);
        wait(&status);  // Wait for child to complete
        printf("Child process completed\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

// Define maximum number of processes
#define MAX_PROCESSES 100

// Process States
enum ProcessState {
    NEW,
    READY,
    RUNNING,
    BLOCKED,
    TERMINATED
};

// Process Control Block Structure
typedef struct PCB {
    int pid;                    // Process ID
    int parent_pid;             // Parent Process ID
    enum ProcessState state;    // Current state

    // CPU Registers
    int program_counter;        // Address of next instruction
    int accumulator;            // Accumulator register
    int registers[8];           // General purpose registers

    // Memory Management
    int memory_limit;           // Maximum memory
    int memory_base;            // Base address

    // Scheduling Information
    int priority;               // Process priority
    int cpu_time_used;          // Total CPU time used

    // I/O Status
    int open_files[10];         // Array of file descriptors

    // Accounting
    int arrival_time;           // When process entered system
    int completion_time;        // When process finished

    // Pointers
    struct PCB *next;           // Next PCB in queue
} PCB;

// Function to create a new PCB
PCB* create_PCB(int pid, int parent_pid, int priority) {
    PCB *new_pcb = (PCB*)malloc(sizeof(PCB));

    new_pcb->pid = pid;
    new_pcb->parent_pid = parent_pid;
    new_pcb->state = NEW;
    new_pcb->program_counter = 0;
    new_pcb->accumulator = 0;
    new_pcb->priority = priority;
    new_pcb->cpu_time_used = 0;
    new_pcb->arrival_time = 0;
    new_pcb->completion_time = 0;
    new_pcb->next = NULL;

    return new_pcb;
}

// Function to display PCB information
void display_PCB(PCB *pcb) {
    printf("PID: %d\n", pcb->pid);
    printf("Parent PID: %d\n", pcb->parent_pid);
    printf("State: %d\n", pcb->state);
    printf("Priority: %d\n", pcb->priority);
    printf("Program Counter: %d\n", pcb->program_counter);
    printf("CPU Time Used: %d\n", pcb->cpu_time_used);
}

int main() {
    // Create a sample process
    PCB *process1 = create_PCB(1001, 1000, 5);

    printf("Process Control Block Example\n");
    printf("============================\n\n");

    process1->state = READY;
    display_PCB(process1);

    return 0;
}
